var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그러니까…","JPN":"だから……","ENG":"So...","TWN":"所以…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"유일한 재산으로 갖고 다니던 화분의 흙 속에서, 그 칼을 발견했단 말이지?","JPN":"唯一の財産として持ち歩いていた植木鉢の土の中から、そのナイフを見つけたのだな？","ENG":"You found that knife in the dirt of the pot you were carrying around as your only property?","TWN":"你是在你唯一的財產，也就是那個花盆裡發現這把刀的？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그리고 그 화분은 소냐가 처음 고아원에 들어갈 때부터 함께 맡겨진 물건이었고요!","JPN":"そして、その植木鉢はソーニャが孤児院に預けられる時から一緒に預けられた物でしたね！","ENG":"And you had that pot even when you first entered the orphanage!","TWN":"然後這個花盆從你去孤兒院時，就一直陪伴著你！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Right.","TWN":"嗯。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아마 그 사람은 검을 일부러 화분에 넣어뒀을 거야.","JPN":"たぶんあの人はわざと刀を植木鉢に入れたんだ。","ENG":"I think he put the knife in the pot on purpose.","TWN":"這把刀應該是他特意放進花盆裡的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"제아무리 무법자가 많은 프론트베이라도, 꼬마애를 상대로 화분을 훔쳐가는 도둑은 없을 테니까.","JPN":"いくら無法者だらけのフロントベイでも、子どもを相手に植木鉢を奪っていく泥棒はないはずだから。","ENG":"Even with all those criminals around, nobody would steal a flower pot from a child.","TWN":"畢竟就算前灣的歹徒再怎麼多，也不至於去偷一個小孩的花盆。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"헉, 그럼 소냐는 아버지가 남긴 유일한 유산으로 생선을 썰고 있었던 거네요?!","JPN":"へえ、じゃあソーニャはお父さんが残してくれた唯一の遺産で魚をさばいていたんですね！？","ENG":"*Gasp.* Then Sonya, you were slicing fish with the only inheritance your father left you?!","TWN":"嚇！所以你拿爸爸留給你唯一的遺產去殺魚嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"역시 해적! 해적스러움을 넘어선 초월적인 패륜!","JPN":"さすが海賊！　海賊らしさを越えた超越的な親不孝！","ENG":"So piratey! You've transcended pirateness! It's just downright disrespectful!","TWN":"不愧是海盜！簡直超越海盜的倫理道德！"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"자기 아빠 재산이 실린 배를 턴 애가 할 소린 아닌 것 같은데.","JPN":"自分のパパの財産がある船を盗んだ人が言う言葉ではないと思うけど。","ENG":"Says the girl who robbed the ship with her father's wealth.","TWN":"你這個偷走自己父親財產的人沒資格說我吧？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그 칼에 새겨진 표식은 대해적 에이버리의 심볼이야. 알고 있었나?","JPN":"そのナイフに刻まれている印は大海賊エイバリーのシンボルだ。知っていたか？","ENG":"That symbol on the knife is the symbol of Great Pirate Avery. Were you aware?","TWN":"你知道刀上刻的記號是大海盜艾維利的標誌嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"워낙 유명하니까.","JPN":"まぁ、有名だからな。","ENG":"Yeah, since he's famous and all.","TWN":"嗯，因為它很有名。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"대해적에게 자식이 있었단 얘긴 처음 듣는데.","JPN":"大海賊に子どもがいたという話は初めて聞くけど。","ENG":"I didn't know the Great Pirate had a kid.","TWN":"我從來沒聽說過大海盜有孩子。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"여태 아무에게도 말하지 않은 건가?","JPN":"今まで誰にも言わなかったのか？","ENG":"Have you kept it a secret so far?","TWN":"你沒告訴過其他人嗎？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"관심 없어.","JPN":"興味ない。","ENG":"I don't really care.","TWN":"沒興趣"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"해적 핏줄인 게 자랑도 아니고, 애초에 날 키워준 건 얼굴도 모르는 아버지가 아니라 고아원이었으니까.","JPN":"親が海賊なのが別に自慢でもないし、そもそもあたしを育ててくれたのは顔も知らないお父さんではなく、孤児院だったから。","ENG":"It's not a good thing to be a descendant of a pirate. Plus, the orphanage raised me, not my father.","TWN":"我沒有對自己的海盜血統感到驕傲，當初養育我的也不是那不露面的父親，而是孤兒院。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그 사람에게 난… 있으나 없으나 아무래도 좋은 존재였을 거야.","JPN":"あの人にあたしは……別にいてもいなくてもいい存在だったんだ。","ENG":"To him... I was probably a nobody.","TWN":"對那個人來說，我…不過是可有可無的存在。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐….","JPN":"ソーニャ……","ENG":"Sonya...","TWN":"索妮雅…"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"볼일이 끝났으니, 이 섬에 더 머물 이유는 없겠군.","JPN":"用は終わったから、これ以上この島にとどまる必要はない。","ENG":"Well, since we're done here, we should get going.","TWN":"既然事情都辦完了，也就沒必要再留在這座島上。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아가씨들이 타고 온 배는 어디에 있지?","JPN":"お嬢さんたちが乗っていた船はどこだ？","ENG":"Where's the ship you brought?","TWN":"小丫頭，你們的船在哪裡？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아, 그거 말이지.","JPN":"あ、それなんだけど。","ENG":"Oh, that.","TWN":"我們船喔？"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"이게 얼마 전에 산 배라고? 그렇다고 하기엔 꼴이 말이 아닌데.","JPN":"これが買ったばかりの船だと？　それにしては酷い様だが。","ENG":"You bought this ship recently? It's looking quite weary for it to be new.","TWN":"你說這艘船才剛買沒多久？看起來不像呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"영광의 상처죠. 우린 크라켄과 싸웠거든요!","JPN":"栄光の傷です。私たちはクラーケンと戦ったのですから！","ENG":"They're battle scars. We fought Kraken!","TWN":"這是榮譽的傷疤，我們和克拉肯戰鬥過！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"크라켄? 그 괴물과 싸우고 살아 돌아왔다고…?","JPN":"クラーケン？　あの化け物と戦って生きて帰ってきたのか……？","ENG":"Kraken? You fought that beast and survived...?","TWN":"克拉肯？你們和那個怪物交手還活著回來…？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"싸웠다고 하기엔 일방적으로 당했어. 우린 간신히 떨쳐내고 도망쳤을 뿐이지.","JPN":"戦ったというには一方的にやられた。あたしたちは辛うじて逃げただけ。","ENG":"Not exactly fought. It was one-sided. We barely managed to shake it off and escape.","TWN":"其實也不算是有交手，應該說是被他追著打。我們好不容易才甩掉他逃跑的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…그래도 제법이군. 누구도 쉽게 성공하지 못했던 일인데 말이야.","JPN":"……でもやるな。誰も簡単には成功できなかったことなのに。","ENG":"...Still. Impressive. It's not an easy task.","TWN":"…那也很厲害，之前從來沒有人能從他手裡逃脫。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"저쪽이 자네들의 선장인가?","JPN":"あっちが君たちの船長か？","ENG":"Is that your captain?","TWN":"那個人就是你們的船長嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"드르렁-","JPN":"ぐうー","ENG":"*Snore...*","TWN":"呼嚕——"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"맞아. 고장 난 배에 밧줄을 묶고 반나절 동안 헤엄쳤더니 그대로 골아 떨어졌어.","JPN":"そう。壊れた船をロープで繋いで3時間ぐらい泳いだら、そのまま寝てしまった。","ENG":"Yeah. She tied the broken ship onto a rope and swam with it for half a day. Now she's dead asleep.","TWN":"沒錯，她拉著我們的船在海裡游了半天，現在昏睡中。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선장이 그렇게 고생하지 않았다면, 우린 아직도 바다를 표류하고 있었겠지.","JPN":"船長があんなに苦労しなかったら、あたしたちは今も海の中で漂流していたな。","ENG":"If she hadn't worked so hard to get us out, we'd still be drifting in the vast sea.","TWN":"要不是船長，我們現在還在海上飄盪呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"드문 광경이군. 선원들을 위해 희생하는 해적 선장이라니.","JPN":"珍しい光景だな。船員のために犠牲する海賊船長とは。","ENG":"A rare sight indeed. A pirate captain that makes sacrifices for her crew.","TWN":"真是難得，海盜船長為她的船員犧牲自己。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어쩔 수 없었어요. 배를 끌만큼 무식하게 힘센 건 선장님뿐이었거든요!","JPN":"仕方ありません。船を引っ張れるほどバカ力なのは船長しかいませんでしたから！","ENG":"We didn't have a choice. She was the only one brutishly strong enough to drag the ship!","TWN":"這也是沒辦法的事，唯一能拉得動船的人就只有船長！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"탈리, 넌 말을 아끼는 편이 이미지에 이로워.","JPN":"タリー、あなたは何も言わない方がいいと思うよ。","ENG":"Tallie, you're better off keeping your mouth shut.","TWN":"塔莉，你還是少說話比較好。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫, 안타깝지만 지금 세상을 떠도는 해적은 남을 위해 고생하는 부류와는 거리가 멀거든.","JPN":"ハハハ、残念だが今の世の中を出回っている海賊は他人のために苦労する連中とは距離がある。","ENG":"Gah hah hah, it's a shame, but the pirates roaming the seas right now are not the type to work hard for others.","TWN":"哈哈哈，遺憾的是，現在這個世代的的海盜是不會為他人犧牲自己的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"해적이 된다는 건, 세상이 솔선수범이나 자기희생처럼 숭고한 이치로만 돌아가지 않는단 걸 안다는 거니까.","JPN":"海賊になるというのは、世の中が率先と自己犠牲のような気高い理想だけでは回らないということを知っているという意味だから。","ENG":"Since, becoming a pirate means that one is aware that the world doesn't revolve around good examples and self-sacrifice.","TWN":"當上海盜，就表示不再遵守以身作則、自我犧牲這種崇高原則。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그럼 잭 아저씬 어쩌다 해적이 된 건데요?","JPN":"ではジャックおじさんはどうして海賊になったのですか？","ENG":"Then how did you become a pirate, Jack?","TWN":"那傑克大叔為什麼會成為海盜？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그건, 마하 섬의 절벽에서 바라보는 일출이 끝내주게 낭만적이기 때문이지.","JPN":"それは、マッハ島の崖っぷちから見る日の出がとてつもなくロマンチックだからだ。","ENG":"It's because the view of the sunrise from the cliff of Macha Island is the dream.","TWN":"因為在瑪查島的懸崖上看日出特別浪漫。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"대해적 에이버리가 했던 말이네.","JPN":"大海賊エイバリーが言っていた言葉だね。","ENG":"You're quoting the Great Pirate Avery.","TWN":"這是大海盜艾維利說過的話。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"음? 아가씨도 알고 있나?","JPN":"ん？　お嬢さんも知っているのか？","ENG":"Mm? You've heard of it?","TWN":"嗯？你也知道嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"우리 선장도 가끔 그런 소릴 하거든.","JPN":"うちの船長も時にそれを言うんだ。","ENG":"Our captain says that too.","TWN":"我們船長有時也會這麼說。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"에이버리를 존경하는 해적들은 마하 섬을 찾아내는 걸 궁극의 목표로 삼기도 할 정도니까.","JPN":"エイバリーを尊敬する海賊はマッハ島を探すことを究極の目標にすることもあるらしいから。","ENG":"Pirates who look up to Avery often set their life goal as finding Macha Island.","TWN":"海盜都非常欽佩艾維利，他們一直把找到瑪查島當作終極目標。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 지금의 마하 섬은 관리국이 접근금지령을 내린 지역 중에서도 가장 위험한 곳이지.","JPN":"でも今のマッハ島は管理局が接近禁止命令を出した地域の中でも最も危険な場所だ。","ENG":"But Macha Island is now the most treacherous area among the locations that the Administration has restricted.","TWN":"但如今，瑪查島是管理局封鎖的所有區域中最危險的一個。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"맞아. 크라켄이 도사리는 심해역에서도 가장 중심에 있는 섬이니까.","JPN":"そう。クラーケンが住んでいる深海域の中で最も中心にある島だから。","ENG":"Right. Since it's right in the heart of Kraken's territory.","TWN":"沒錯，那座島位於克拉肯出沒的深海域的正中心。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"재미있지 않나?","JPN":"面白くないか？","ENG":"Funny, isn't it?","TWN":"是不是很有趣？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"멋진 광경을 보려면 목숨을 걸어야 한다는 게 말이야.","JPN":"素晴らしい風景を見るためには命をかけなければならないということが。","ENG":"That you have to risk your life for a fantastic view.","TWN":"你必須冒著生命危險才能看到的壯麗景象。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그런 낭만이 있으니까 해적이 되는 거죠!","JPN":"そんなロアンがあるから海賊になるんです！","ENG":"Well, we're all pirates because we have that kind of dream!","TWN":"這就是海盜的浪漫！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫핫.","JPN":"ハハハ。","ENG":"Gah hah hah!","TWN":"哈哈哈。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그래, 요즘 해적들은 낭만을 빼면 남는 게 없는 장사긴 하지.","JPN":"そうだ、最近の海賊はロマンを抜けば残るものがないな。","ENG":"Right. The dream is the only thing pirates have these days.","TWN":"沒錯，如今海盜這行就只剩下浪漫了。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"바다를 누비고 다닐 권한은 헌터 자격을 가진 사람들에게만 허용되고, 범죄이력이 있는 해적들은 정식으로 기용하지도 않으니 말이야.","JPN":"海に出る権限はハンター資格を持っている人にのみ許されていて、犯罪履歴のある海賊は正式に雇うこともないから。","ENG":"Roaming the sea is only permitted to those qualified as hunters, and they don't officially hire any pirates with a criminal record.","TWN":"只有擁有獵人身份的人，才能獲准在海上航行，有犯罪記錄的海盜根本無法被任用。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"딱히 상관없어. 어차피 프론트베이는 현상범이 현상범을 잡아도 보수를 주는 곳이잖아?","JPN":"別にいい。どうせフロントベイは手配者が手配者を捕まえても報酬を貰える所だろ？","ENG":"It doesn't matter, though. Front Bay pays you even if you're a wanted criminal who hands in another wanted criminal.","TWN":"這有什麼關係，反正前灣是個可以黑吃黑的地方不是嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"현상금 토큰을 가지고 있으면 죄도 사면받을 수 있고요!","JPN":"懸賞金トークンあれば罪も許してくれますしね！","ENG":"And you can get pardoned if you have enough bounty tokens!","TWN":"只要有賞金代幣，一切的罪都可以得赦免！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…그래. 관리국도 사실 알고 있는 거지.","JPN":"……そう。管理局も実は知っているのだ。","ENG":"...Yes. Which means that the Administration is aware.","TWN":"…嗯，這是管理局也默認的。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"외지에서 온 용병도, 말 안 듣는 골칫거리들도…","JPN":"よそから来た傭兵も、言うことを聞かない困り者たちも……","ENG":"Foreign mercenaries and stubborn troublemakers...","TWN":"來自外地的雇傭兵也好、不聽話的搗亂分子也好…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"결국 이 침식의 시대를 살아가기 위해선 함께 협력해야 할 존재라는 걸.","JPN":"結局この侵食の時代を生きていくためには共に協力しなければならない、ということを。","ENG":"They have to cooperate in order to survive this era of Corruption.","TWN":"總而言之，我們必須一起努力，才能在這崩壞的時代生存下去。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그럼 뭐해요. 헌터들은 해적만 보면 허구한 날 싸우자고 시비 거는데.","JPN":"そんなこと言っても。ハンターは海賊を見るといつも喧嘩売っていますけど。","ENG":"But they don't know that. Hunters don't miss the chance to pick fights whenever they spot a pirate.","TWN":"問題是，獵人只要看到海盜就會挑釁找麻煩。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"난 이해해. 헌터들에게 해적은 자기들 밥벌이 수단을 빼앗는 범죄자일 뿐이니까.","JPN":"あたしは理解できる。ハンターにとって海賊は自分の稼ぎを邪魔する犯罪者でしかないから。","ENG":"I understand them. To hunters, pirates are nothing but thieves who are stealing their means of living.","TWN":"我明白，因為對獵人來說，海盜就只是搶走他們飯碗的罪犯。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그리고 해적들은 헌터가 벌이는 무분별한 채굴과 사냥이 바다를 분노하게 만든다고 생각해서 싫어하지.","JPN":"そして海賊はハンターがやらかしている無分別な採掘と狩りが海を怒らせていると思うから嫌っている。","ENG":"And pirates hate hunters because they think hunters anger the ocean with their reckless mining and hunting.","TWN":"而海盜則是憎恨獵人不計後果地採礦和狩獵，他們認為這會激怒大海。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"정말 답이 없네요.","JPN":"本当に難題ですね。","ENG":"It's hopeless.","TWN":"完全無解呢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"양쪽 모두의 목숨이 걸린 일이 아니고서야, 어떻게 그 둘이 협력하는 모습을 기대하겠어요?","JPN":"両方とも命がかかった問題でない限り、協力する姿は期待できませんね。","ENG":"We can't expect the two to cooperate unless both of their lives are in danger.","TWN":"除非他們雙方都命懸一線，否則你怎麼能指望他們能合作呢？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"핫핫, 그렇지. 정말로 그래.","JPN":"ハハ、そうだ。間違いない。","ENG":"Gah hah, right. Truly so.","TWN":"哈哈，沒錯。確實是這樣。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_CREW","text":{"KOREA":"선장, 지시하신대로 저 친구들 배를 살펴봤는데요.","JPN":"船長、言われた通りにあの人たちの船を見てみたのですが。","ENG":"Captain, we took a look at their ship, just as you ordered.","TWN":"船長，我已經按照指示檢查完她們的船。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_FRONTBAY_JACK_CREW","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_CREW","text":{"KOREA":"서로 망가진 부품이 달라서 배는 둘 중 하나만 고칠 수 있을 것 같습니다.","JPN":"お互い壊れた部品が違って船はどちらか一つだけ直せそうです。","ENG":"They're broken in different areas, so only one of the ships can be repaired.","TWN":"因為二艘船損壞的零件不同，只能選一艘船修復。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PIRATE_FRONTBAY_JACK_CREW","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇게 됐다는군.","JPN":"だそうだ。","ENG":"So it is.","TWN":"是嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우리 배에 남는 선실이 있으니 일단 함께 육지로 돌아가지 않겠나?","JPN":"私たちの船に船室が残っているから、取りあえず一緒に陸地に戻らないか？","ENG":"Our ship has some extra cabins. Would you like to join us to return to the mainland?","TWN":"我們的船上還有剩餘的船艙，不如先坐我們的船，回到岸上吧？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"당신네들 배를 고치고 우리 배는 남겨두자는 거지?","JPN":"あなたたちの船を修理して、あたしたちの船は捨てるってこと？","ENG":"So you're suggesting we fix your ship and leave ours here?","TWN":"你想把你的船修好，把我們的船留下？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"뭐, 지금으로선 선택의 여지가 없네.","JPN":"まぁ、今の状況じゃ他に選択肢はないか。","ENG":"Well, I guess we have no choice.","TWN":"不過我們現在也別無選擇。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐는 몰라도 저희 선장님은 자기 배 건드린 사람을 절대 가만두지 않을 걸요?!","JPN":"ソーニャはともかく私たちの船長は自分の船に触った人は絶対許さないと思いますけど！？","ENG":"Sonya aside, our captain would never let you tinker with our ship!","TWN":"索妮雅怎麼說我不管，但我敢打賭船長絕對不會讓任何人破壞她的船！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"우리 선실에는 푹신한 침대도 있지.","JPN":"うちの船室にはフカフカなベットもある。","ENG":"Our cabins have comfortable beds.","TWN":"我們船艙裡的床非常軟喔。"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"푸, 푹신한 침대…?!","JPN":"ふ、フカフカなベット……！？","ENG":"C-comfortable beds...?!","TWN":"軟…軟軟的床…？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_CREW","text":{"KOREA":"케케, 해적 아가씨들을 위해 맛있는 미트스튜도 준비해 뒀다고?","JPN":"ケケ、海賊お嬢さんたちのために美味しいミートシチューも作っておいたぞ？","ENG":"Keh heh, we even have some delicious meat stew ready for you lassies.","TWN":"嘿嘿，還有特別為你們準備的美味燉肉喔？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_JACK_CREW","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"맛있는 미트스튜…?!","JPN":"美味しいミートシチュー……！？","ENG":"Delicious meat stew...?!","TWN":"美味的燉肉…？"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_JACK_CREW","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"드르렁-","JPN":"ぐうー","ENG":"*Snore...*","TWN":"呼嚕——"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그 배, 샤워실도 있나요?!","JPN":"その船、シャワー室もありますか！？","ENG":"Does that ship also have a shower?!","TWN":"你的船，有浴室嗎？！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};